LID (contains numbers 1–9) # - Only rows and columns may contain conflicts fillBlocks &lt;- function(sudoku, blocks) { for (block in blocks) { values &lt;- sudoku[block] # Find numbers missing in this block missing &lt;- setdiff(1:9, values) # Fill empty cells randomly with missing numbers zeros &lt;- which(values == 0) values[zeros] &lt;- sample(missing) sudoku[block] &lt;- values } return(sudoku) } # ========================================================== # GENERATE A NEIGHBOR (STATE TRANSITION) # We create a &quot;new candidate solution&quot; by: # - Picking a random 3x3 block # - Swapping two NON-FIXED cells inside it # # This ensures: # - Block remains valid # - Only row/column structure changes swapCells &lt;- function(sudoku, fixed, block) { repeat { idx &lt;- sample(1:nrow(block), 2) c1 &lt;- block[idx[1],] c2 &lt;- block[idx[2],] # Only swap if both are NOT fixed if (fixed[c1[1],c1[2]] == 0 &amp;&amp; fixed[c2[1],c2[2]] == 0) { # Swap values temp &lt;- sudoku[c1[1],c1[2]] sudoku[c1[1],c1[2]] &lt;- sudoku[c2[1],c2[2]] sudoku[c2[1],c2[2]] &lt;- temp return(sudoku) } } } 2.4 Simulated Annealing Solver The solveSudoku function applies a simulated annealing optimization process to solve a Sudoku puzzle by iteratively reducing conflicts in rows and columns while preserving valid 3×3 blocks (Constraint Decomposition). It begins by identifying fixed cells, generating an initial valid state by randomly filling each block, and estimating an initial temperature (sigma) that controls how freely the algorithm explores different configurations. During each iteration, it proposes a new candidate solution by swapping two non-fixed cells within a random block, evaluates whether the change improves the error (number of conflicts), and accepts it either if it is better or with a probability that allows occasional acceptance of worse solutions to escape local minima. As the algorithm progresses, the temperature gradually decreases (cooling), making the search increasingly focused and less random, while continuously tracking the best solution found. The process continues until either a conflict-free Sudoku (error = 0) is reached or a maximum number of iterations is exceeded, at which point the best available solution is returned. 2.4.1 Code Notes: 2.4.1.1 Simulated Annealing Parameters The line sigma &lt;- estimateInitialSigma(sudoku, fixed, blocks) computes a data-driven starting temperature for the simulated annealing process by estimating how much the error typically changes under random swaps. This is important because it scales the acceptance probability so that early in the search the algorithm neither accepts too many bad moves (too random) nor rejects them all (gets stuck). By setting sigma based on the actual problem landscape, it improves the solver’s balance between exploration and convergence, making the optimization more stable and effective. The Sudoku Solver result is embedded in the bottom of the executed code chunk solveSudoku &lt;- function(sudoku) { # Identify fixed cells fixed &lt;- fixSudokuValues(sudoku) # Get block definitions blocks &lt;- getBlocks() # Create INITIAL VALID STATE sudoku &lt;- fillBlocks(sudoku, blocks) #sigma &lt;- 2 # &quot;temperature&quot; (controls randomness) sigma &lt;- estimateInitialSigma(sudoku, fixed, blocks) cooling &lt;- 0.995 # how fast temperature decreases maxIter &lt;- 100000 # maximum attempts # Track best solution seen so far best &lt;- sudoku bestScore &lt;- calcErrors(sudoku) # ----------------------------- # MAIN OPTIMIZATION LOOP # ----------------------------- for (iter in 1:maxIter) { # Step 1: Generate candidate solution block &lt;- blocks[[sample(1:9,1)]] newSudoku &lt;- swapCells(sudoku, fixed, block) # Step 2: Evaluate current vs new state currentCost &lt;- calcErrors(sudoku) newCost &lt;- calcErrors(newSudoku) # Difference in cost delta &lt;- newCost - currentCost # ----------------------------------------------------- # Step 3: Acceptance rule (CORE of Simulated Annealing) # ----------------------------------------------------- # # Case 1: If new solution is BETTER (delta &lt;= 0) # -&gt; always accept # # Case 2: If WORSE (delta &gt; 0) # -&gt; accept with probability: # # exp(-delta / temperature) # # This allows the algorithm to: # - Escape local minima # - Explore wider solution space early on # if (delta &lt;= 0 || runif(1) &lt; exp(-delta/sigma)) { sudoku &lt;- newSudoku } # Step 4: Track best solution found currentCost &lt;- calcErrors(sudoku) if (currentCost &lt; bestScore) { best &lt;- sudoku bestScore &lt;- currentCost } # Step 5: COOLING (reduce randomness over time) # # Early: high temperature → more random exploration # Late: low temperature → greedy refinement sigma &lt;- sigma * cooling # Step 6: Stop if solved if (bestScore == 0) { cat(&quot;Solved at iteration:&quot;, iter, &quot;
